int dp[N][21];
void solve(int CASE)
{
	int n, q; cin >> n >> q;
	string s; cin >> s; s = ' ' + s + s;
	var a = vector<ll>(2 * n + 1);
	fa(i, 1, n)cin >> a[i], a[i + n] = a[i];

	// 找离 i 最近的与 i 类别相同的位置的下一个位置
	var pos = vector<int>(26);
	var nex = vector<int>(2 * n + 1);
	fb(i, 2 * n, 1) {
		int c = s[i] - 'A';
		if (pos[c])nex[i] = pos[c] + 1;
		pos[c] = i;
	}
	fa(i, 1, 2 * n)dp[i][0] = nex[i];
	fa(j, 1, 20)
		fa(i, 1, 2 * n)
		dp[i][j] = dp[dp[i][j - 1]][j - 1];

	while (q--) {
		int op; cin >> op;
		if (op == 1) {
			ll x, y; cin >> x >> y;
			a[x] = y, a[x + n] = y;
		}
		else {
			ll l, r; cin >> l >> r;
			ll ans = 0;
			if (l > r)r += n;
			int now = l;
			// 最多 26 * 20
			while (now <= r) {
				fb(i, 20, 0) 
					if (dp[now][i] and dp[now][i] <= r + 1) 
						now = dp[now][i];
				if (now <= r)ans += a[now], now++;
			}
			cout << ans << endl;
		}
	}
	return;
}
